    const adj = new Array(n).fill().map(() => []);
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    let maxLen = 0;

    // Try all possible starting nodes
    for (let start = 0; start < n; start++) {
        // Use BFS to explore all paths starting from 'start'
        const visited = new Array(n).fill(false);
        const queue = [];
        queue.push([start, [start], [...visited]]);

        while (queue.length > 0) {
            const [node, path, visitedArr] = queue.shift();
            const currentChar = label[node];
            const pathStr = path.map(i => label[i]).join('');

            // Check if the path forms a palindrome
            if (pathStr === pathStr.split('').reverse().join('')) {
                maxLen = Math.max(maxLen, pathStr.length);
